questions = [
{"id":"3521","tipo":"multipla","disciplina":"Matemática","tema":"Álgebra","subtema":"Inequações do 1º grau","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Resolva a inequação 3x - 6 > 0. O conjunto solução é:","alternativa_a":"x > 2","alternativa_b":"x < 2","alternativa_c":"x > -2","alternativa_d":"x ≥ 2","alternativa_e":"x = 2","resposta_correta":"a","explicacao":"3x > 6 → x > 2. Intervalo: (2, +∞).","resposta":""},
{"id":"3522","tipo":"multipla","disciplina":"Física","tema":"Termodinâmica","subtema":"Ciclo de Carnot","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Uma máquina de Carnot opera entre 500 K e 250 K. Sua eficiência máxima é:","alternativa_a":"50%","alternativa_b":"25%","alternativa_c":"75%","alternativa_d":"100%","alternativa_e":"500%","resposta_correta":"a","explicacao":"η_Carnot = 1 - T_fria/T_quente = 1 - 250/500 = 1 - 0,5 = 0,5 = 50%.","resposta":""},
{"id":"3523","tipo":"multipla","disciplina":"Química","tema":"Orgânica","subtema":"Cetonas e aldeídos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A diferença entre aldeído e cetona está em:","alternativa_a":"O aldeído tem o carbonila no carbono terminal; a cetona tem no carbono interno","alternativa_b":"O aldeído tem fórmula CₙH₂ₙ₊₁OH","alternativa_c":"As cetonas são sempre mais reativas que os aldeídos","alternativa_d":"O aldeído não possui grupo carbonila","alternativa_e":"As cetonas ocorrem apenas em compostos aromáticos","resposta_correta":"a","explicacao":"Carbonila (C=O): aldeído → C terminal (CHO); cetona → C interno (CO entre dois outros carbonos). Ex.: metanal (formaldeído, H-CHO) vs propanona (acetona, CH₃-CO-CH₃).","resposta":""},
{"id":"3524","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Fluxo de energia","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Na pirâmide de energia, a eficiência ecológica média entre níveis tróficos é de aproximadamente:","alternativa_a":"10% — regra dos 10%","alternativa_b":"90%","alternativa_c":"50%","alternativa_d":"1%","alternativa_e":"100%","resposta_correta":"a","explicacao":"Regra dos 10%: apenas ~10% da energia de um nível trófico é transferida ao seguinte (o restante é perdido como calor pela respiração). Razão pela qual cadeias alimentares raramente têm mais de 4-5 elos.","resposta":""},
{"id":"3525","tipo":"multipla","disciplina":"História","tema":"História Geral","subtema":"Guerra do Vietnã","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A Guerra do Vietnã (1955-1975) terminou com:","alternativa_a":"A vitória do Vietnã do Norte comunista e a reunificação do país","alternativa_b":"A divisão permanente entre Norte e Sul","alternativa_c":"A vitória dos EUA e instalação de regime capitalista","alternativa_d":"Armistício sem vencedor claro","alternativa_e":"Intervenção da ONU que criou novo estado independente","resposta_correta":"a","explicacao":"Guerra do Vietnã: EUA apoiaram o Sul (capitalista) contra o Norte (Ho Chi Minh, comunista, apoiado por URSS/China). EUA se retiraram em 1973 (Acordos de Paris). 1975: Saigon caiu para o Norte → reunificação como República Socialista do Vietnã (1976). Derrota americana emblemática da Guerra Fria.","resposta":""},
{"id":"3526","tipo":"multipla","disciplina":"Geografia","tema":"Regiões Brasileiras","subtema":"Região Norte","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"A região Norte do Brasil tem como característica marcante:","alternativa_a":"Maior área do país (~45%) com menor densidade demográfica","alternativa_b":"A maior população urbana do Brasil","alternativa_c":"O maior PIB industrial do país","alternativa_d":"O maior índice de desmatamento do Cerrado","alternativa_e":"A maior produção de soja do Brasil","resposta_correta":"a","explicacao":"Região Norte: 7 estados (AM, PA, RO, AC, RR, AP, TO), ~45% do território brasileiro, mas apenas ~9% da população. Amazônia domina o bioma. Menor densidade demográfica (~4 hab/km²).","resposta":""},
{"id":"3527","tipo":"multipla","disciplina":"Inglês","tema":"Gramática","subtema":"Reported Speech","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Direct speech: 'I am happy.' In reported speech:","alternativa_a":"She said she was happy.","alternativa_b":"She said she is happy.","alternativa_c":"She said I am happy.","alternativa_d":"She says she was happy.","alternativa_e":"She told she was happy.","resposta_correta":"a","explicacao":"Reported speech: recua-se o tempo verbal (backshift). 'am' → 'was'. 'I' → 'she'. 'say' + 'that' (optional). 'told' precisa de objeto: 'she told me she was happy.'","resposta":""},
{"id":"3528","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia da Mente","subtema":"Inteligência artificial e consciência","dificuldide":"Difícil","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"O Teste de Turing proposto por Alan Turing em 1950 serve para verificar se:","alternativa_a":"Uma máquina demonstra comportamento inteligente indistinguível do humano","alternativa_b":"Um computador pode processar mais dados que o cérebro humano","alternativa_c":"A inteligência artificial é consciente","alternativa_d":"Um robô consegue se mover de forma autônoma","alternativa_e":"Um algoritmo pode resolver qualquer problema matemático","resposta_correta":"a","explicacao":"Teste de Turing: um avaliador humano conversa por texto com um humano e uma máquina sem saber qual é qual. Se não conseguir distinguir, a máquina 'passou'. Não testa consciência — testa comportamento. Searle critica com 'Quarto Chinês': simular entendimento ≠ entender.","resposta":""},
{"id":"3529","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Saúde","subtema":"Determinantes sociais da saúde","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Os determinantes sociais da saúde incluem:","alternativa_a":"Renda, educação, habitação, saneamento e condições de trabalho","alternativa_b":"Apenas fatores genéticos hereditários","alternativa_c":"Somente o acesso a hospitais e médicos","alternativa_d":"Exclusivamente a alimentação e exercício físico","alternativa_e":"O comportamento individual sem influência do contexto social","resposta_correta":"a","explicacao":"OMS: determinantes sociais da saúde são condições em que as pessoas nascem, crescem, vivem, trabalham e envelhecem — moldadas por forças econômicas, sociais e políticas. Renda, educação, raça, gênero, saneamento determinam mais a saúde do que o acesso a serviços médicos.","resposta":""},
{"id":"3530","tipo":"multipla","disciplina":"Literatura","tema":"Conto Brasileiro","subtema":"Guimarães Rosa — contos","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Em 'A Terceira Margem do Rio' de Guimarães Rosa, o pai que viaja permanentemente em uma canoa simboliza:","alternativa_a":"A condição humana de estar entre dois mundos sem pertencer a nenhum","alternativa_b":"A fuga da responsabilidade familiar","alternativa_c":"A tradição de pesca do sertão mineiro","alternativa_d":"A loucura causada pelo sol do sertão","alternativa_e":"A morte como libertação dos problemas cotidianos","resposta_correta":"a","explicacao":"'A Terceira Margem do Rio': o pai constrói uma canoa e vive no meio do rio indefinidamente, sem margem, sem destino. A 'terceira margem' é o espaço do inexplicável, da transcendência, do limiar entre ser e não-ser. O conto é uma fábula existencial sobre o mistério da existência humana, a incompreensão entre gerações e a impossibilidade de nomear o sagrado.","resposta":""},
{"id":"3531","tipo":"multipla","disciplina":"Matemática","tema":"Geometria Analítica","subtema":"Inclinação e coeficiente angular","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Uma reta tem coeficiente angular m=2 e passa pelo ponto (0,3). Sua equação é:","alternativa_a":"y = 2x + 3","alternativa_b":"y = 3x + 2","alternativa_c":"y = 2x - 3","alternativa_d":"y = -2x + 3","alternativa_e":"y = 2 + 3x","resposta_correta":"a","explicacao":"Forma slope-intercept: y = mx + b. m=2, ponto (0,3) → b=3. y = 2x + 3.","resposta":""},
{"id":"3532","tipo":"multipla","disciplina":"Física","tema":"Mecânica","subtema":"Momento angular","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Uma bailarina gira com os braços abertos. Ao fechar os braços, sua velocidade angular:","alternativa_a":"Aumenta — conservação do momento angular","alternativa_b":"Diminui","alternativa_c":"Permanece igual","alternativa_d":"Depende da massa dos braços","alternativa_e":"Varia aleatoriamente","resposta_correta":"a","explicacao":"L = I×ω = constante (sem torque externo). Fechar os braços reduz o momento de inércia I → para conservar L, ω aumenta. Análogo ao patinador no gelo.","resposta":""},
{"id":"3533","tipo":"multipla","disciplina":"Química","tema":"Ambiental","subtema":"Efeito estufa","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O principal gás responsável pelo efeito estufa antropogênico é:","alternativa_a":"CO₂ (dióxido de carbono)","alternativa_b":"O₂ (oxigênio)","alternativa_c":"N₂ (nitrogênio)","alternativa_d":"Ar (mistura)","alternativa_e":"He (hélio)","resposta_correta":"a","explicacao":"CO₂ é o principal GEE (gás de efeito estufa) de origem humana, proveniente da queima de combustíveis fósseis e desmatamento. Outros GEEs: CH₄ (metano), N₂O, vapores d'água, F-gases. O CO₂ é o mais abundante e persistente na atmosfera.","resposta":""},
{"id":"3534","tipo":"multipla","disciplina":"Biologia","tema":"Parasitologia","subtema":"Doenças tropicais — Malária","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A malária é transmitida pelo mosquito Anopheles e causada pelo protozoário Plasmodium. O ciclo no humano inclui:","alternativa_a":"Fase hepática (assintomática) seguida de fase eritrocítica (febre cíclica)","alternativa_b":"Infecção direta dos neurônios causando meningite","alternativa_c":"Multiplicação exclusiva no sistema linfático","alternativa_d":"Destruição dos leucócitos com imunossupressão","alternativa_e":"Infecção pelo contato com água contaminada","resposta_correta":"a","explicacao":"Ciclo da malária no humano: esporozoítos (picada) → hepatócitos (período pré-eritrocítico, assintomático, 7-30 dias) → merozoítos → eritrócitos (ciclo eritrocítico: 48h P.vivax/P.falciparum, 72h P.malariae) → lise dos eritrócitos = febre cíclica. Tratamento: cloroquina, artemisinina (resistência crescente).","resposta":""},
{"id":"3535","tipo":"multipla","disciplina":"História","tema":"História do Brasil","subtema":"Governo Dilma — impeachment","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O impeachment de Dilma Rousseff (2016) foi fundamentado em:","alternativa_a":"Pedaladas fiscais — manipulação das contas públicas para esconder o déficit","alternativa_b":"Condenação em processo por corrupção pessoal","alternativa_c":"Golpe militar apoiado pelas Forças Armadas","alternativa_d":"Renúncia voluntária por pressão popular","alternativa_e":"Cassação por crime de responsabilidade por uso de aeronaves militares","resposta_correta":"a","explicacao":"Pedaladas fiscais: o governo Dilma atrasou repasses a bancos públicos (BB, CEF, BNDES) para pagamento de programas sociais, maquiando o déficit fiscal — acusação de crime de responsabilidade. Debate político intenso: parte da oposição e acadêmicos chamaram de 'golpe parlamentar'. Em 2016, o Senado aprovou o impeachment por 61 votos a 20.","resposta":""},
{"id":"3536","tipo":"multipla","disciplina":"Geografia","tema":"Petróleo","subtema":"Pré-sal brasileiro","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A descoberta do pré-sal no Brasil (2006-2007) é estrategicamente importante porque:","alternativa_a":"Colocou o Brasil entre os maiores produtores mundiais de petróleo","alternativa_b":"Tornou o Brasil autossuficiente em gasolina refinada","alternativa_c":"Eliminou a necessidade de importação de derivados","alternativa_d":"Permitiu o abandono completo das fontes renováveis","alternativa_e":"Resolveu definitivamente o problema energético nacional","resposta_correta":"a","explicacao":"Pré-sal (camada rochosa a 5-7 km abaixo do leito marinho): reservas descobertas na Bacia de Santos e Campos. Brasil saltou de 2 mi para 3+ mi barris/dia de produção. Entrou no Top 10 mundial. Debate: marco regulatório (partilha de produção vs. concessão), royalties, destinação para educação e saúde (EC 29 e Lei 12.858).","resposta":""},
{"id":"3537","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia da Linguagem","subtema":"Saussure — linguística estrutural","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Para Ferdinand de Saussure, o signo linguístico é composto por:","alternativa_a":"Significante (imagem acústica) e significado (conceito)","alternativa_b":"Palavra e seu referente no mundo real","alternativa_c":"Emissor e receptor da mensagem","alternativa_d":"Fonema e morfema","alternativa_e":"Denotação e conotação","resposta_correta":"a","explicacao":"Saussure (Curso de Linguística Geral, 1916): signo = união indissociável de significante (imagem acústica — a 'face sonora' da palavra, como /arvore/) e significado (conceito — a ideia, não a coisa real). Arbitrariedade do signo: a relação entre significante e significado é convencional, não natural.","resposta":""},
{"id":"3538","tipo":"multipla","disciplina":"Sociologia","tema":"Cultura","subtema":"Multiculturalismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O multiculturalismo, como política e perspectiva teórica, defende:","alternativa_a":"O reconhecimento e a coexistência respeitosa de diversas culturas numa sociedade","alternativa_b":"A assimilação de minorias à cultura dominante","alternativa_c":"A superioridade de certas culturas sobre outras","alternativa_d":"A separação física de grupos culturais diferentes","alternativa_e":"A eliminação das diferenças culturais em prol da unidade nacional","resposta_correta":"a","explicacao":"Multiculturalismo: reconhecimento da diversidade cultural como legítima e enriquecedora. Políticas: ensino de línguas minoritárias, representação cultural, combate à discriminação. Debate: integração vs. fragmentação social. Charles Taylor: 'política do reconhecimento' das identidades culturais.","resposta":""},
{"id":"3539","tipo":"multipla","disciplina":"Literatura","tema":"Literatura de Cabo Verde","subtema":"Claridade — Movimento","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O Movimento Claridade em Cabo Verde (1936) buscava:","alternativa_a":"Afirmar a identidade cabo-verdiana mestiça e questionar o colonialismo português","alternativa_b":"Imitar os modelos literários do Romantismo português","alternativa_c":"Negar qualquer influência africana na cultura cabo-verdiana","alternativa_d":"Defender a assimilação total à cultura europeia","alternativa_e":"Criar uma literatura exclusivamente em língua crioula","resposta_correta":"a","explicacao":"Claridade (revista, 1936, Cabo Verde): movimento que valorizou a identidade crioula — mistura de culturas africanas e portuguesas. Influências: Modernismo brasileiro (Gilberto Freyre, Jorge Amado). Temas: seca, emigração, sodade (saudade cabo-verdiana). Autores: Baltasar Lopes, Manuel Lopes, Jorge Barbosa. Ruptura com a ideia de que a cultura africana era inferior.","resposta":""},
{"id":"3540","tipo":"multipla","disciplina":"Matemática","tema":"Funções","subtema":"Função logarítmica","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Qual o valor de log₂(32)?","alternativa_a":"5","alternativa_b":"16","alternativa_c":"4","alternativa_d":"6","alternativa_e":"3","resposta_correta":"a","explicacao":"log₂(32) = x → 2^x = 32 = 2^5. Logo x = 5.","resposta":""},
{"id":"4391","tipo":"dissertativa","disciplina":"Matemática","tema":"Geometria Plana","subtema":"Área do trapézio","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Um trapézio tem bases de 8 cm e 12 cm, e altura de 5 cm. Calcule sua área e compare com um retângulo de mesma altura e base média.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Área do trapézio = (B+b)/2 × h = (12+8)/2 × 5 = 10 × 5 = 50 cm². Base média = (B+b)/2 = (12+8)/2 = 10 cm. Retângulo de base 10 e altura 5: A = 10×5 = 50 cm². São iguais! A área do trapézio é equivalente à do retângulo com base média e mesma altura — demonstração visual da fórmula.","resposta":"Área = 50 cm². Equivale a retângulo de base média (10 cm) × altura (5 cm) = 50 cm²."},
{"id":"4392","tipo":"dissertativa","disciplina":"Física","tema":"Eletricidade","subtema":"Lei de Coulomb","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Duas cargas de 2×10⁻⁶ C e 3×10⁻⁶ C estão separadas por 0,1 m. Calcule a força elétrica entre elas. (k=9×10⁹ N·m²/C²)","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"F = k×q₁×q₂/r². F = (9×10⁹ × 2×10⁻⁶ × 3×10⁻⁶) / (0,1)² = (9×10⁹ × 6×10⁻¹²) / 0,01 = (54×10⁻³) / 0,01 = 5,4 N. Como ambas as cargas são positivas, a força é repulsiva.","resposta":"F = 5,4 N (repulsiva, pois ambas as cargas são positivas)"},
{"id":"4393","tipo":"dissertativa","disciplina":"Química","tema":"Estequiometria","subtema":"Rendimento de reação","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Na síntese da amônia: N₂ + 3H₂ → 2NH₃. Se 28 g de N₂ reagirem completamente, quantas gramas de NH₃ são produzidas? (M: N=14, H=1)","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"M(N₂) = 28 g/mol. n(N₂) = 28/28 = 1 mol. Pela estequiometria: 1 mol N₂ → 2 mol NH₃. M(NH₃) = 14+3 = 17 g/mol. m(NH₃) = 2 mol × 17 g/mol = 34 g.","resposta":"34 g de NH₃"},
{"id":"4394","tipo":"dissertativa","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema cardiovascular — pressão arterial","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O que é pressão arterial? O que significam os valores 120/80 mmHg? Quais são os fatores que levam à hipertensão?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Pressão arterial: força que o sangue exerce sobre as paredes das artérias. 120/80 mmHg: 120 = pressão sistólica (ventrículo esquerdo contraindo, sístole); 80 = pressão diastólica (coração relaxado, diástole). OMS: normal < 120/80; pré-hipertensão 120-139/80-89; hipertensão ≥ 140/90. Fatores de risco para hipertensão: excesso de sal (retém água, aumenta volume sanguíneo), obesidade, sedentarismo, estresse (adrenalina → vasoconstrição), tabagismo, álcool, herança genética, idade. Hipertensão = 'assassino silencioso' — aumenta risco de AVC, infarto, insuficiência renal.","resposta":"120 = sistólica (sístole); 80 = diastólica (diástole). Hipertensão: sal, obesidade, estresse, sedentarismo — risco de AVC e infarto."},
{"id":"4395","tipo":"dissertativa","disciplina":"História","tema":"História do Brasil","subtema":"Borracha — Ciclo econômico","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O Ciclo da Borracha (1850-1912) transformou a Amazônia. Explique sua dinâmica econômica, social e seu declínio.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Ciclo da Borracha: demanda industrial da 2ª Revolução Industrial (pneumáticos, impermeabilização). Amazônia = único fornecedor mundial de seringa (Hevea brasiliensis). Sistema do aviamento: seringalistas (donos das terras) financiavam seringueiros (migrantes nordestinos) com mercadorias a preços abusivos, gerando dívidas impagáveis — semi-escravidão. Manaus e Belém enriqueceram (Teatro Amazonas, 1896). Declínio: Wickham (inglês) contrabandeou sementes para Kew Gardens (1876); plantações britânicas na Malásia e Ceilão → borracha asiática mais barata e abundante → colapso dos preços (1910-12). Segundo ciclo: WWII (1942-45), 'batalha da borracha' — Vargas mobilizou nordestinos ('soldados da borracha').","resposta":"Borracha amazônica = monopólio mundial até 1912. Sistema aviamento = semi-escravidão. Declínio: plantações asiáticas a partir de sementes roubadas. Teatro Amazonas como legado."},
{"id":"4396","tipo":"dissertativa","disciplina":"Geografia","tema":"Florestas","subtema":"Desmatamento na Amazônia","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Quais são as principais causas e consequências do desmatamento na Amazônia?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Causas: (1) Expansão da agropecuária (soja e pecuária bovina = ~80% do desmatamento — arco do desmatamento RO, MT, PA, MA); (2) Garimpo ilegal (mercúrio contamina rios e comunidades indígenas); (3) Madeireiros ilegais; (4) Grilagem (fraude fundiária); (5) Infraestrutura (BR-163, hidrelétricas). Consequências: (1) Emissões de CO₂ (desflorestamento = ~50% das emissões brasileiras); (2) Extinção de espécies (Amazônia = 10% da biodiversidade mundial); (3) Alteração do regime de chuvas (rios voadores); (4) Degradação de terras indígenas; (5) Aquecimento regional. PRODES/INPE monitora. Desmatamento caiu de 27.000 km²/ano (2004) para 4.000 (2012) e voltou a subir — política ambiental é fator determinante.","resposta":"Causas: agropecuária, garimpo, madeira ilegal, grilagem. Consequências: CO₂, extinção de espécies, alteração climática, degradação de TIs."},
{"id":"4397","tipo":"dissertativa","disciplina":"Português","tema":"Literatura","subtema":"Murilo Rubião e o realismo fantástico","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Murilo Rubião é considerado precursor do realismo fantástico na América Latina. Quais são as características de sua prosa?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Murilo Rubião (1916-1991, MG): iniciou publicações antes de Borges e García Márquez terem ampla circulação no Brasil. Obra: 'O Ex-Mágico', 'A Estrela Vermelha'. Características: (1) Naturalização do fantástico — personagens e narradores aceitam eventos impossíveis sem espanto (animais que falam, pessoas que se multiplicam, personagens que crescem indefinidamente); (2) Tom burocrático/cotidiano que contrasta com o absurdo; (3) Influência kafkiana (absurdo existencial); (4) Epígrafes bíblicas — dimensão alegórica e existencial; (5) Personagens entediados com sua existência incomum. O fantástico não assusta — é fonte de tédio e angústia. Precursor nacional do que García Márquez faria internacionalmente.","resposta":"Realismo fantástico: naturalização do impossível, tom burocrático, influência de Kafka, epígrafes bíblicas. Precursor latino-americano antes de García Márquez."},
{"id":"4398","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia Política","subtema":"Anarquismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O que é anarquismo? Quais são suas principais correntes e como se diferenciam do marxismo?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Anarquismo: filosofia política que rejeita toda forma de autoridade hierárquica (Estado, Igreja, capital) como ilegítima. Objetivo: sociedade baseada em associações livres e voluntárias. Principais correntes: anarcocomunismo (Kropotkin — propriedade coletiva, ajuda mútua); anarcossindicalismo (ação direta do movimento operário — CGT francesa); anarcoindividualismo (Stirner — primado do indivíduo). Diferenças do marxismo: marxistas aceitam uma fase transitória com o Estado proletário (ditadura do proletariado → comunismo); anarquistas rejeitam completamente o Estado — qualquer poder do Estado é corruptível. Debate histórico: Bakunin vs. Marx na 1ª Internacional. União Soviética: para anarquistas, traiu a revolução ao criar Estado autoritário.","resposta":"Anarquismo: rejeita todo Estado e hierarquia. Correntes: comunista (Kropotkin), sindicalista, individualista. Diferença do marxismo: rejeita completamente o Estado, incluindo a fase transitória."},
{"id":"4399","tipo":"dissertativa","disciplina":"Sociologia","tema":"Método Sociológico","subtema":"Pesquisa qualitativa vs quantitativa","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Diferencie pesquisa qualitativa e quantitativa em ciências sociais. Quando usar cada abordagem?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Pesquisa quantitativa: trabalha com dados numéricos, amostras representativas, análise estatística, busca generalizações e causalidades. Instrumentos: questionários fechados, surveys, índices (IDH, Gini). Ideal para: medir frequências, correlações, tendências populacionais (ex.: IBGE, Datafolha). Pesquisa qualitativa: analisa sentidos, significados, experiências subjetivas. Instrumentos: entrevistas em profundidade, observação participante, etnografia, análise de discurso. Ideal para: compreender processos sociais complexos, perspectivas de grupos específicos, contextos culturais. Ex.: pesquisa sobre experiência de mulheres vítimas de violência. Abordagem mista: combina as duas (triangulação). Não há hierarquia — a escolha depende do problema de pesquisa.","resposta":"Quantitativa: números, generalização, surveys. Qualitativa: significados, entrevistas, etnografia. Abordagem mista combina as duas conforme o problema."},
{"id":"4400","tipo":"dissertativa","disciplina":"Literatura","tema":"Poesia Brasileira Contemporânea","subtema":"Ferreira Gullar","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Ferreira Gullar percorreu do Concretismo ao Neoconcretismo e depois à poesia engajada. Explique essa trajetória e a importância do 'Poema Sujo' (1975).","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Ferreira Gullar (1930-2016, MA): iniciou no Concretismo (Noigandres, anos 50), depois fundou o Neoconcretismo (1959, Manifesto Neoconcreto) com Lygia Clark e Hélio Oiticica — reintroduzindo a subjetividade e a fenomenologia contra o rigor formalista do concretismo. Anos 60-70: poesia engajada política, exílio na Argentina durante a Ditadura. 'Poema Sujo' (1975, escrito em Buenos Aires): obra-síntese escrita ao saber de doença grave — longo poema que mistura memória de São Luís (infância), erotismo, política e reflexão sobre a morte. Considerado um dos grandes poemas da língua portuguesa. Título 'sujo' = recusa ao purismo formal, abraça a vida em toda sua impureza.","resposta":"Do Concretismo ao Neoconcretismo (subjetividade + fenomenologia) à poesia engajada. 'Poema Sujo' (exílio, 1975): síntese de memória, erotismo e morte — recusa ao purismo formal."},
]

